from openpyxl import load_workbook
from openpyxl.utils import range_boundaries

INPUT_PATH = "/app/spreadsheets/1_22-47_input.xlsx"
OUTPUT_PATH = "/app/output/1_22-47_output.xlsx"
SHEET_NAME = "sheet1"
SOURCE_COLS = (1, 2, 3)      # A:C -> ITEM, NAME, REF
HELPER_COL = 10              # J
OUTPUT_RANGE = "F2:H20"

HEADER_VALUES = {"ITEM", "NAME", "REF", "LIST"}


def is_blank(value):
    return value is None or (isinstance(value, str) and value.strip() == "")


def normalized(value):
    if value is None:
        return ""
    if isinstance(value, str):
        return value.strip()
    return value


def is_header_row(values):
    text_values = {str(value).strip().upper() for value in values if not is_blank(value)}
    return bool(text_values) and text_values.issubset(HEADER_VALUES)


def collect_source_rows(ws):
    rows = []
    seen_name_ref = set()

    for row_idx in range(1, ws.max_row + 1):
        values = [ws.cell(row_idx, col).value for col in SOURCE_COLS]
        item, name, ref = values

        if all(is_blank(value) for value in values):
            continue
        if is_header_row(values):
            continue
        if is_blank(name) or is_blank(ref):
            continue

        duplicate_key = (normalized(name), normalized(ref))
        if duplicate_key in seen_name_ref:
            continue

        seen_name_ref.add(duplicate_key)
        rows.append(tuple(values))

    return rows


def collect_helper_names(ws):
    helper_names = []
    seen = set()

    for row_idx in range(1, ws.max_row + 1):
        value = ws.cell(row_idx, HELPER_COL).value
        if is_blank(value):
            continue

        name = str(value).strip()
        if name.upper() in HEADER_VALUES:
            continue

        key = name.upper()
        if key in seen:
            continue
        seen.add(key)
        helper_names.append(name)

    return helper_names


def sort_rows(rows, helper_names):
    if not helper_names:
        return sorted(rows, key=lambda row: str(row[1]).strip().upper())

    result = []
    used_indices = set()

    for helper_name in helper_names:
        helper_key = helper_name.upper()
        for index, row in enumerate(rows):
            if index in used_indices:
                continue
            if str(row[1]).strip().upper() == helper_key:
                result.append(row)
                used_indices.add(index)

    for index, row in enumerate(rows):
        if index not in used_indices:
            result.append(row)

    return result


def write_output(ws, rows):
    min_col, min_row, max_col, max_row = range_boundaries(OUTPUT_RANGE)
    output_height = max_row - min_row + 1

    for row_offset in range(output_height):
        for col_offset in range(max_col - min_col + 1):
            ws.cell(min_row + row_offset, min_col + col_offset).value = None

    for row_offset, row_values in enumerate(rows[:output_height]):
        for col_offset, value in enumerate(row_values):
            ws.cell(min_row + row_offset, min_col + col_offset).value = value


def main():
    workbook = load_workbook(INPUT_PATH)
    worksheet = workbook[SHEET_NAME]

    source_rows = collect_source_rows(worksheet)
    helper_names = collect_helper_names(worksheet)
    sorted_rows = sort_rows(source_rows, helper_names)
    write_output(worksheet, sorted_rows)

    workbook.save(OUTPUT_PATH)


if __name__ == "__main__":
    main()
